+/**
+ * History Service - Tracks agent activity and prompt/response history.
+ *
+ * Provides comprehensive history tracking including:
+ * - Prompt and response recording
+ * - Token usage tracking
+ * - Outcome recording
+ * - Full-text search
+ * - Export capabilities
+ */
+
+import { eq, desc, and, gte, lte, like, sql, count } from "drizzle-orm";
+import { db } from "../db";
+import { history as historyTable, agents as agentsTable } from "../db/schema";
+import { logger } from "./logger";
+import { getCorrelationId } from "../middleware/correlation";
+
+// ============================================================================
+// Types
+// ============================================================================
+
+export type HistoryOutcome = "success" | "failure" | "interrupted" | "timeout";
+
+export interface HistoryEntry {
+  id: string;
+  agentId: string;
+  timestamp: Date;
+  prompt: string;
+  promptTokens: number;
+  responseSummary: string;
+  responseTokens: number;
+  durationMs: number;
+  outcome: HistoryOutcome;
+  error?: string;
+  tags: string[];
+  starred: boolean;
+  replayCount: number;
+  metadata?: Record<string, unknown>;
+}
+
+export interface HistoryInput {
+  prompt: string;
+  promptTokens?: number;
+  contextPackId?: string;
+  tags?: string[];
+  metadata?: Record<string, unknown>;
+}
+
+export interface HistoryOutput {
+  responseSummary: string;
+  responseTokens?: number;
+  outcome: HistoryOutcome;
+  error?: string;
+}
+
+export interface HistoryStats {
+  totalEntries: number;
+  totalPromptTokens: number;
+  totalResponseTokens: number;
+  averageDurationMs: number;
+  outcomeDistribution: Record<HistoryOutcome, number>;
+  entriesByDay: Array<{ date: string; count: number }>;
+}
+
+export interface HistoryQueryOptions {
+  agentId?: string;
+  outcome?: HistoryOutcome[];
+  starred?: boolean;
+  startDate?: Date;
+  endDate?: Date;
+  search?: string;
+  tags?: string[];
+  limit?: number;
+  cursor?: string;
+}
+
+// ============================================================================
+// ID Generation
+// ============================================================================
+
+function generateHistoryId(): string {
+  const timestamp = Date.now().toString(36);
+  const random = Math.random().toString(36).slice(2, 8);
+  return `hist_${timestamp}_${random}`;
+}
+
+// ============================================================================
+// History Entry Management
+// ============================================================================
+
+/**
+ * Create a new history entry when an agent interaction starts.
+ */
+export async function createHistoryEntry(
+  agentId: string,
+  input: HistoryInput
+): Promise<HistoryEntry> {
+  const correlationId = getCorrelationId();
+  const log = logger.child({ correlationId, agentId });
+
+  const id = generateHistoryId();
+  const now = new Date();
+
+  const entry: HistoryEntry = {
+    id,
+    agentId,
+    timestamp: now,
+    prompt: input.prompt,
+    promptTokens: input.promptTokens ?? estimateTokens(input.prompt),
+    responseSummary: "",
+    responseTokens: 0,
+    durationMs: 0,
+    outcome: "success",
+    tags: input.tags ?? [],
+    starred: false,
+    replayCount: 0,
+    metadata: input.metadata,
+  };
+
+  // Store in database
+  await db.insert(historyTable).values({
+    id,
+    agentId,
+    command: "send", // Type of operation
+    input: {
+      prompt: input.prompt,
+      promptTokens: entry.promptTokens,
+      contextPackId: input.contextPackId,
+      tags: input.tags,
+      metadata: input.metadata,
+    },
+    output: null,
+    durationMs: 0,
+    createdAt: now,
+  });
+
+  log.info(
+    { entryId: id, promptTokens: entry.promptTokens },
+    "History entry created"
+  );
+
+  return entry;
+}
