+/**
+ * Star or unstar a history entry.
+ */
+export async function toggleStar(entryId: string): Promise<HistoryEntry | null> {
+  const entry = await getHistoryEntry(entryId);
+  if (!entry) {
+    return null;
+  }
+
+  // Get current row to update
+  const rows = await db
+    .select()
+    .from(historyTable)
+    .where(eq(historyTable.id, entryId))
+    .limit(1);
+
+  if (rows.length === 0) {
+    return null;
+  }
+
+  const row = rows[0]!;
+  const inputData = (row.input as Record<string, unknown>) ?? {};
+  const currentStarred = (inputData.starred as boolean) ?? false;
+
+  // Toggle starred in input JSON
+  await db
+    .update(historyTable)
+    .set({
+      input: {
+        ...inputData,
+        starred: !currentStarred,
+      },
+    })
+    .where(eq(historyTable.id, entryId));
+
+  entry.starred = !currentStarred;
+
+  logger.info({ entryId, starred: entry.starred }, "History entry star toggled");
+
+  return entry;
+}
