+  const headers = [
+    "id",
+    "agentId",
+    "timestamp",
+    "prompt",
+    "promptTokens",
+    "responseSummary",
+    "responseTokens",
+    "durationMs",
+    "outcome",
+    "tags",
+    "starred",
+  ];
