+  const rows = entries.map((e) => [
+    e.id,
+    e.agentId,
+    e.timestamp.toISOString(),
+    escapeCSV(e.prompt),
+    e.promptTokens,
+    escapeCSV(e.responseSummary),
+    e.responseTokens,
+    e.durationMs,
+    e.outcome,
+    e.tags.join(";"),
+    e.starred ? "true" : "false",
+  ]);
+
+  return [headers.join(","), ...rows.map((r) => r.join(","))].join("\n");
+}
