+// ============================================================================
+// Output Extraction
+// ============================================================================
+
+export type ExtractionType = "code_blocks" | "json" | "file_paths" | "urls" | "errors" | "custom";
+
+export interface ExtractionMatch {
+  content: string;
+  lineStart: number;
+  lineEnd: number;
+  metadata?: Record<string, unknown>;
+}
+
+export interface ExtractionResult {
+  matches: ExtractionMatch[];
+  totalMatches: number;
+}
+
+/**
+ * Extract structured content from output text.
+ */
+export function extractFromOutput(
+  output: string,
+  type: ExtractionType,
+  options: { language?: string; customPattern?: string } = {}
+): ExtractionResult {
+  const lines = output.split("\n");
+  const matches: ExtractionMatch[] = [];
+
+  switch (type) {
+    case "code_blocks": {
+      // Extract markdown code blocks
+      let inBlock = false;
+      let blockStart = 0;
+      let blockContent: string[] = [];
+      let blockLang = "";
+
+      for (let i = 0; i < lines.length; i++) {
+        const line = lines[i]!;
+        if (line.startsWith("```")) {
+          if (!inBlock) {
+            inBlock = true;
+            blockStart = i;
+            blockLang = line.slice(3).trim();
+            blockContent = [];
+          } else {
+            if (!options.language || blockLang === options.language) {
+              matches.push({
+                content: blockContent.join("\n"),
+                lineStart: blockStart + 1,
+                lineEnd: i - 1,
+                metadata: { language: blockLang },
+              });
+            }
+            inBlock = false;
+          }
+        } else if (inBlock) {
+          blockContent.push(line);
+        }
+      }
+      break;
+    }
+
+    case "json": {
+      // Extract JSON objects/arrays
+      const jsonPattern = /(\{[\s\S]*?\}|\[[\s\S]*?\])/g;
+      let match;
+      while ((match = jsonPattern.exec(output)) !== null) {
+        try {
+          JSON.parse(match[1]!);
+          const startLine = output.slice(0, match.index).split("\n").length - 1;
+          const endLine = output.slice(0, match.index + match[1]!.length).split("\n").length - 1;
+          matches.push({
+            content: match[1]!,
+            lineStart: startLine,
+            lineEnd: endLine,
+          });
+        } catch {
+          // Not valid JSON, skip
+        }
+      }
+      break;
+    }
+
+    case "file_paths": {
+      // Extract file paths
+      const pathPattern = /(?:^|\s)((?:\/[\w.-]+)+\/?|(?:[A-Za-z]:)?\\(?:[\w.-]+\\)*[\w.-]+)/gm;
+      let match;
+      while ((match = pathPattern.exec(output)) !== null) {
+        const lineNum = output.slice(0, match.index).split("\n").length - 1;
+        matches.push({
+          content: match[1]!.trim(),
+          lineStart: lineNum,
+          lineEnd: lineNum,
+        });
+      }
+      break;
+    }
+
+    case "urls": {
+      // Extract URLs
+      const urlPattern = /https?:\/\/[^\s<>"{}|\\^`[\]]+/gi;
+      let match;
+      while ((match = urlPattern.exec(output)) !== null) {
+        const lineNum = output.slice(0, match.index).split("\n").length - 1;
+        matches.push({
+          content: match[0],
+          lineStart: lineNum,
+          lineEnd: lineNum,
+        });
+      }
+      break;
+    }
+
+    case "errors": {
+      // Extract error patterns
+      const errorPatterns = [
+        /Error:\s*.+/gi,
+        /Exception:\s*.+/gi,
+        /FAILED:\s*.+/gi,
+        /error\[\w+\]:\s*.+/gi,
+        /TypeError:\s*.+/gi,
+        /SyntaxError:\s*.+/gi,
+        /ReferenceError:\s*.+/gi,
+      ];
+
+      for (const pattern of errorPatterns) {
+        let match;
+        while ((match = pattern.exec(output)) !== null) {
+          const lineNum = output.slice(0, match.index).split("\n").length - 1;
+          matches.push({
+            content: match[0],
+            lineStart: lineNum,
+            lineEnd: lineNum,
+          });
+        }
+      }
+      break;
+    }
+
+    case "custom": {
+      if (options.customPattern) {
+        try {
+          const pattern = new RegExp(options.customPattern, "gi");
+          let match;
+          while ((match = pattern.exec(output)) !== null) {
+            const lineNum = output.slice(0, match.index).split("\n").length - 1;
+            matches.push({
+              content: match[0],
+              lineStart: lineNum,
+              lineEnd: lineNum,
+            });
+          }
+        } catch {
+          // Invalid regex
+        }
+      }
+      break;
+    }
+  }
+
+  return {
+    matches,
+    totalMatches: matches.length,
+  };
+}
